1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	function calculateQuotePremium(items: Array<{ type: string }>): number {
12	  const policyBasePremium = items.reduce(
13	    (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
14	    0
15	  );
16	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
17	  return policyBasePremium + firstInsuranceSurcharge + PROCESSING_FEE;
18	}
19	
20	interface QuoteResult {
21	  premium: number;
22	}
23	
24	interface ScenarioOutcome {
25	  results: QuoteResult[];
26	}
27	
28	export function processScenario(scenario: {
29	  customer: { yearsWithMHPCO: number };
30	  steps: Array<{ op: string; items?: Array<{ type: string }> }>;
31	}): ScenarioOutcome {
32	  const results = scenario.steps.map((step) => {
33	    const premium = calculateQuotePremium(step.items ?? []);
34	    return { premium };
35	  });
36	  return { results };
37	}
